hooks.command:
python3 -c "
import json, sys, subprocess, os
try:
    d = json.load(sys.stdin)
    cmd = d.get('tool_input', d).get('command', '')
    if 'git push' in cmd and 'no-verify' not in cmd:
        result = subprocess.run(['node', 'scripts/sop-check.js'], capture_output=True, text=True)
        if result.returncode != 0:
            out = json.dumps({'hookSpecificOutput': {'hookEventName': 'PreToolUse', 'additionalContext': '[SOP GATE] Pre-deploy check FAILED. Fix issues before pushing:\n' + result.stdout + result.stderr}})
            sys.stdout.write(out)
except:
    pass
"
